// Verifica Authorization Header
const expectedSecret = $env['N8N_SECRET'];

if (!expectedSecret) {
  throw new Error('500 Internal Server Error: N8N_SECRET not configured in n8n environment');
}

const req = $('Webhook').first().json;
const headers = req.headers || {};
const authHeader = headers.authorization;
const ip = headers['x-forwarded-for'] || 'unknown';

// --- PREPARAÇÃO PARA RATE LIMITING ---
// Exemplo futuro: 
// const staticData = $getWorkflowStaticData('global');
// staticData[ip] = (staticData[ip] || 0) + 1;
// if (staticData[ip] > LIMIT) throw new Error('429 Too Many Requests');
// -------------------------------------

if (!authHeader || authHeader !== `Bearer ${expectedSecret}`) {
  // LOG GERAL (visível no painel do n8n / docker logs)
  const partialHeader = authHeader ? authHeader.substring(0, 15) + '...' : 'none';
  console.warn(JSON.stringify({
    event: 'UNAUTHORIZED_ACCESS_ATTEMPT',
    timestamp: new Date().toISOString(),
    ip: ip,
    providedHeader: partialHeader,
    webhookId: 'cockpit-performance'
  }));

  // Interrompe a execução lançando um erro
  throw new Error('401 Unauthorized: Invalid Authentication Token');
}

return $input.all();

// ============================================================
// STEP 1 — NORMALIZAR
// Lê os dados brutos do Sheets e normaliza tipos
// ============================================================

const gestor = $('Webhook').first().json.query?.gestor || null;

function parseBRL(value) {
  if (value === null || value === undefined || value === '') return 0;
  const str = String(value)
    .replace(/R\$\s*/g, '')
    .replace(/\./g, '')
    .replace(',', '.')
    .trim();
  const num = parseFloat(str);
  return isNaN(num) ? 0 : num;
}

const rows = $input.all();

const normalized = rows
  .map(item => {
    const r = item.json;
    return {
      cliente:     String(r['Cliente'] || '').trim(),
      gestor:      String(r['Gestor'] || '').trim(),
      investimento: parseBRL(r['Total de Investimento']),
      leads:        parseBRL(r['Total de RESULTADOS (Gerenciador)']),
      metaCPA:      parseBRL(r['Meta de CPA']),
    };
  })
  .filter(r => r.cliente !== '');

// Filtro por gestor via query param (opcional)
const filtered = gestor
  ? normalized.filter(r => r.gestor.toLowerCase() === gestor.toLowerCase())
  : normalized;

return filtered.map(r => ({ json: r }));

// ============================================================
// STEP 2 — AGREGAR + CALCULAR MÉTRICAS
// ============================================================

const rows = $input.all().map(i => i.json);

// Agrupa por cliente
const map = {};
for (const row of rows) {
  if (!map[row.cliente]) {
    map[row.cliente] = {
      cliente:      row.cliente,
      investimento: 0,
      leads:        0,
      metaCPA:      0,
      _metaCount:   0,
    };
  }
  map[row.cliente].investimento += row.investimento;
  map[row.cliente].leads        += row.leads;
  if (row.metaCPA > 0) {
    map[row.cliente].metaCPA   += row.metaCPA;
    map[row.cliente]._metaCount++;
  }
}

// Calcula CPL e status
const resultado = Object.values(map).map(c => {
  const cpl = c.leads > 0
    ? parseFloat((c.investimento / c.leads).toFixed(2))
    : 0;

  // Usa média de meta (caso cliente tenha múltiplas linhas)
  const metaCPA = c._metaCount > 0
    ? c.metaCPA / c._metaCount
    : 0;

  let status = 'verde';
  if (metaCPA > 0) {
    if (cpl > metaCPA)              status = 'vermelho';
    else if (cpl > metaCPA * 0.8)   status = 'amarelo';
  }

  return {
    cliente: c.cliente,
    leads:   c.leads,
    cpl,
    status,
  };
});

// Ordena: vermelho → amarelo → verde
const ordem = { vermelho: 0, amarelo: 1, verde: 2 };
resultado.sort((a, b) => ordem[a.status] - ordem[b.status]);

// Empacota o payload final em um único item
return [{
  json: {
    status:        'ok',
    totalClientes: resultado.length,
    data:          resultado,
    geradoEm:      new Date().toISOString(),
  }
}];
